from flask import Flask, request, session
import xml.etree.ElementTree as ET

app = Flask(__name__)

@app.route('/', methods=['POST'])
def saml_callback():
    # Validate untrusted input and use secure platform APIs
    if not request.is_json:
        return 'Invalid request', 400
    
    # Parse SAML XML response using xml.etree.ElementTree
    root = ET.fromstring(request.get_data())
    
    # Extract user attributes from Assertion elements
    for assertion in root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'):
        user_attributes = {}
        for attribute in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            name = attribute.get('Name')
            value = attribute.text
            if name and value:
                user_attributes[name] = value
    
    # Create user session
    session['user'] = user_attributes
    
    return 'SAML response processed successfully', 200